import{_ as a,c as o,o as t,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Fallo de autenticación: Solución de errores 401 | Antigravity-Manager","description":"Aprende el mecanismo de autenticación del proxy de Antigravity Tools, soluciona errores 401. Localiza problemas por auth_mode, api_key, Header, entiende las reglas del modo auto y la excepción /healthz, evita errores de prioridad de Header.","frontmatter":{"title":"Fallo de autenticación: Solución de errores 401 | Antigravity-Manager","sidebarTitle":"Soluciona 401 en 3 minutos","subtitle":"401/Fallo de autenticación: Primero verifica auth_mode, luego verifica Header","description":"Aprende el mecanismo de autenticación del proxy de Antigravity Tools, soluciona errores 401. Localiza problemas por auth_mode, api_key, Header, entiende las reglas del modo auto y la excepción /healthz, evita errores de prioridad de Header.","tags":["FAQ","Autenticación","401","API Key"],"prerequisite":["start-proxy-and-first-client"],"order":2},"headers":[],"relativePath":"es/lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"es/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}'),r={name:"es/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function d(s,e,c,n,l,u){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="_401-fallo-de-autenticacion-primero-verifica-auth-mode-luego-verifica-header" tabindex="-1">401/Fallo de autenticación: Primero verifica auth_mode, luego verifica Header <a class="header-anchor" href="#_401-fallo-de-autenticacion-primero-verifica-auth-mode-luego-verifica-header" aria-label="Permalink to &quot;401/Fallo de autenticación: Primero verifica auth_mode, luego verifica Header&quot;">​</a></h1><h2 id="que-podras-hacer-despues-de-aprender" tabindex="-1">Qué podrás hacer después de aprender <a class="header-anchor" href="#que-podras-hacer-despues-de-aprender" aria-label="Permalink to &quot;Qué podrás hacer después de aprender&quot;">​</a></h2><ul><li>Determinar en 3 minutos si un 401 está siendo bloqueado por el middleware de autenticación de Antigravity Tools</li><li>Entender el &quot;valor efectivo real&quot; de los cuatro modos de <code>proxy.auth_mode</code> (especialmente <code>auto</code>) en tu configuración actual</li><li>Hacer que las solicitudes pasen usando el Header de API Key correcto (y evitar la trampa de prioridad de Headers)</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Al llamar al proxy inverso local, el cliente recibe un error <code>401 Unauthorized</code>:</p><ul><li>Python/OpenAI SDK: lanza <code>AuthenticationError</code></li><li>curl: devuelve <code>HTTP/1.1 401 Unauthorized</code></li><li>Clientes HTTP: código de estado 401 en la respuesta</li></ul><h2 id="¿que-es-401-fallo-de-autenticacion" tabindex="-1">¿Qué es 401/fallo de autenticación? <a class="header-anchor" href="#¿que-es-401-fallo-de-autenticacion" aria-label="Permalink to &quot;¿Qué es 401/fallo de autenticación?&quot;">​</a></h2><p><strong>401 Unauthorized</strong> en Antigravity Tools comúnmente significa: el proxy habilitó la autenticación (determinado por <code>proxy.auth_mode</code>), pero la solicitud no tiene la API Key correcta, o lleva un Header con mayor prioridad que no coincide, por lo que <code>auth_middleware()</code> devuelve 401 directamente.</p><div class="info custom-block"><p class="custom-block-title">Primero confirma si &quot;es el proxy bloqueando&quot;</p><p>Las plataformas upstream también pueden devolver 401, pero este FAQ solo trata &quot;401 causado por autenticación del proxy&quot;. Puedes usar <code>/healthz</code> a continuación para diferenciar rápidamente.</p></div><h2 id="solucion-rapida-haz-esto-en-este-orden" tabindex="-1">Solución rápida (haz esto en este orden) <a class="header-anchor" href="#solucion-rapida-haz-esto-en-este-orden" aria-label="Permalink to &quot;Solución rápida (haz esto en este orden)&quot;">​</a></h2><h3 id="paso-1-usa-healthz-para-determinar-si-la-autenticacion-te-esta-bloqueando" tabindex="-1">Paso 1: Usa <code>/healthz</code> para determinar &quot;si la autenticación te está bloqueando&quot; <a class="header-anchor" href="#paso-1-usa-healthz-para-determinar-si-la-autenticacion-te-esta-bloqueando" aria-label="Permalink to &quot;Paso 1: Usa `/healthz` para determinar &quot;si la autenticación te está bloqueando&quot;&quot;">​</a></h3><p><strong>Por qué</strong><code>all_except_health</code> permitirá <code>/healthz</code>, pero bloqueará otras rutas; esto te ayuda a localizar rápidamente si el 401 proviene de la capa de autenticación del proxy.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Sin ningún Header de autenticación</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>Deberías ver</strong></p><ul><li>Con <code>auth_mode=all_except_health</code> (o <code>auto</code> con <code>allow_lan_access=true</code>): generalmente devuelve <code>200</code></li><li>Con <code>auth_mode=strict</code>: devuelve <code>401</code></li></ul><div class="tip custom-block"><p class="custom-block-title"><code>/healthz</code> en la capa de ruta es GET</p><p>El proxy registra <code>GET /healthz</code> en la ruta (ver <code>src-tauri/src/proxy/server.rs</code>).</p></div><hr><h3 id="paso-2-confirma-el-valor-efectivo-real-de-auth-mode-especialmente-auto" tabindex="-1">Paso 2: Confirma el &quot;valor efectivo real&quot; de <code>auth_mode</code> (especialmente <code>auto</code>) <a class="header-anchor" href="#paso-2-confirma-el-valor-efectivo-real-de-auth-mode-especialmente-auto" aria-label="Permalink to &quot;Paso 2: Confirma el &quot;valor efectivo real&quot; de `auth_mode` (especialmente `auto`)&quot;">​</a></h3><p><strong>Por qué</strong><code>auto</code> no es una &quot;estrategia independiente&quot;, calcula el modo real a ejecutar basándose en <code>allow_lan_access</code>.</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>Condición adicional</th><th>Valor efectivo real (effective mode)</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>Puedes verificar esto en la página API Proxy del GUI</strong>: <code>Allow LAN Access</code> y <code>Auth Mode</code>.</p><hr><h3 id="paso-3-confirma-que-api-key-no-este-vacio-y-que-estas-usando-el-mismo-valor" tabindex="-1">Paso 3: Confirma que <code>api_key</code> no esté vacío y que estás usando el mismo valor <a class="header-anchor" href="#paso-3-confirma-que-api-key-no-este-vacio-y-que-estas-usando-el-mismo-valor" aria-label="Permalink to &quot;Paso 3: Confirma que `api_key` no esté vacío y que estás usando el mismo valor&quot;">​</a></h3><p><strong>Por qué</strong> Cuando la autenticación está habilitada, si <code>proxy.api_key</code> está vacío, <code>auth_middleware()</code> rechazará directamente todas las solicitudes y registrará un error en el log.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>Deberías ver</strong></p><ul><li>En la página API Proxy puedes ver una key que comienza con <code>sk-</code> (el valor predeterminado se genera automáticamente en <code>ProxyConfig::default()</code>)</li><li>Después de hacer clic en &quot;Regenerate/Editar&quot; y guardar, las solicitudes externas se verifican inmediatamente con la nueva key (no es necesario reiniciar)</li></ul><hr><h3 id="paso-4-prueba-con-el-header-mas-simple-primero-no-uses-sdks-complejos-todavia" tabindex="-1">Paso 4: Prueba con el Header más simple primero (no uses SDKs complejos todavía) <a class="header-anchor" href="#paso-4-prueba-con-el-header-mas-simple-primero-no-uses-sdks-complejos-todavia" aria-label="Permalink to &quot;Paso 4: Prueba con el Header más simple primero (no uses SDKs complejos todavía)&quot;">​</a></h3><p><strong>Por qué</strong> El middleware lee primero <code>Authorization</code>, luego <code>x-api-key</code>, y finalmente <code>x-goog-api-key</code>. Si envías múltiples Headers a la vez y el primero es incorrecto, aunque el segundo sea correcto no se usará.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Recomendado: Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>Deberías ver</strong>: <code>HTTP/1.1 200 OK</code> (o al menos ya no es 401)</p><div class="info custom-block"><p class="custom-block-title">Detalles de compatibilidad del proxy con Authorization</p><p><code>auth_middleware()</code> extraerá el valor de <code>Authorization</code> una vez eliminando el prefijo <code>Bearer </code>; si no hay prefijo <code>Bearer </code>, también usará el valor completo como key para comparación. La documentación aún recomienda <code>Authorization: Bearer &lt;key&gt;</code> (más conforme a las convenciones de SDK generales).</p></div><p><strong>Si debes usar <code>x-api-key</code></strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="problemas-comunes-todos-ocurren-realmente-en-el-codigo-fuente" tabindex="-1">Problemas comunes (todos ocurren realmente en el código fuente) <a class="header-anchor" href="#problemas-comunes-todos-ocurren-realmente-en-el-codigo-fuente" aria-label="Permalink to &quot;Problemas comunes (todos ocurren realmente en el código fuente)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fenómeno</th><th>Causa real</th><th>Qué deberías cambiar</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code>, pero las llamadas locales siguen siendo 401</td><td><code>allow_lan_access=true</code> hace que <code>auto</code> se comporte como <code>all_except_health</code></td><td>Deshabilita <code>allow_lan_access</code>, o haz que el cliente lleve la key</td></tr><tr><td>Crees &quot;ya llevé x-api-key&quot;, pero sigue siendo 401</td><td>Simultáneamente llevaste un <code>Authorization</code> no coincidente, el middleware lo usa primero</td><td>Elimina Headers extra, mantén solo uno que sepas que es correcto</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code> sigue siendo 401</td><td>Falta un espacio después de <code>Bearer</code>, no se puede eliminar el prefijo <code>Bearer </code></td><td>Cámbialo a <code>Authorization: Bearer &lt;key&gt;</code></td></tr><tr><td>Todas las solicitudes son 401, el log muestra <code>api_key is empty</code></td><td><code>proxy.api_key</code> está vacío</td><td>Regenera/configura una key no vacía en el GUI</td></tr></tbody></table><h2 id="resumen-de-esta-leccion" tabindex="-1">Resumen de esta lección <a class="header-anchor" href="#resumen-de-esta-leccion" aria-label="Permalink to &quot;Resumen de esta lección&quot;">​</a></h2><ul><li>Primero usa <code>/healthz</code> para localizar si el 401 proviene de la capa de autenticación del proxy</li><li>Luego confirma <code>auth_mode</code> (especialmente el modo efectivo de <code>auto</code>)</li><li>Finalmente lleva solo un Header que sepas que es correcto para verificar (evita la trampa de prioridad de Headers)</li></ul><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos <strong><a href="./../429-rotation/">429/Error de capacidad: Expectativas correctas de rotación de cuentas y误解s de agotamiento de capacidad del modelo</a></strong>.</p><p>Aprenderás:</p><ul><li>Si 429 es &quot;cuota insuficiente&quot; o &quot;limitación upstream&quot;</li><li>Expectativas correctas de rotación de cuentas (cuándo cambia automáticamente, cuándo no)</li><li>Usar configuración para reducir la probabilidad de 429</li></ul></blockquote><hr><h2 id="apendice-referencias-de-codigo-fuente" tabindex="-1">Apéndice: Referencias de código fuente <a class="header-anchor" href="#apendice-referencias-de-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencias de código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para expandir y ver ubicaciones del código fuente</strong></summary><blockquote><p>Actualizado: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Función</th><th>Ruta de archivo</th><th>Línea</th></tr></thead><tbody><tr><td>Enumeración ProxyAuthMode</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L5-L18" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>5-18</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key y valores predeterminados</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>Análisis del modo auto (effective_auth_mode)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/security.rs#L1-L30" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/security.rs</code></a></td><td>1-30</td></tr><tr><td>Middleware de autenticación (extracción y prioridad de Headers, excepción /healthz, permiso OPTIONS)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/auth.rs#L14-L77" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/auth.rs</code></a></td><td>14-77</td></tr><tr><td>Registro de ruta /healthz y orden de middleware</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L170-L193" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>170-193</td></tr><tr><td>Documentación de autenticación (modos y convenciones de cliente)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy/auth.md#L1-L45" target="_blank" rel="noreferrer"><code>docs/proxy/auth.md</code></a></td><td>1-45</td></tr></tbody></table><p><strong>Enumeraciones clave</strong>:</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code>: modos de autenticación</li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code>: analiza <code>auto</code> en una estrategia real</li><li><code>auth_middleware()</code>: ejecuta autenticación (incluye orden de extracción de Headers y excepción /healthz)</li></ul></details>',45)])])}const m=a(r,[["render",d]]);export{h as __pageData,m as default};
